def gameOfLife(board):
    m, n = len(board), len(board[0])
    for r in range(m):
        for c in range(n):
            live = 0
            for i in range(r-1, r+2):
                for j in range(c-1, c+2):
                    if (i == r and j == c) or not (0 <= i < m and 0 <= j < n): continue
                    if board[i][j] & 1: live += 1
            if board[r][c] & 1:
                if 2 <= live <= 3: board[r][c] |= 2
            else:
                if live == 3: board[r][c] |= 2
    for r in range(m):
        for c in range(n): board[r][c] >>= 1

